import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life - Next Generation", () => {
  it.todo("should return empty grid when given empty grid");
  it.todo("should kill a single live cell with 0 neighbors (underpopulation)");
  it.todo("should kill two adjacent live cells (each has 1 neighbor)");
  it.todo("should keep a live cell alive when it has 2 live neighbors (survival)");
  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)");
  it.todo("should transform a vertical 3-cell blinker into a horizontal 3-cell blinker");
  it.todo("should leave a 2x2 block unchanged (still life)");
  it.todo("should support negative coordinates");
});
